import hashlib
from dataclasses import dataclass

@dataclass
class ExperimentAssignment:
    experiment_id: str
    user_id: str       # or session_id if user is anonymous
    arm: str           # "control" or "treatment"
    assigned_at: str   # ISO-8601 timestamp

class ExperimentRouter:
    def __init__(self, experiments: dict[str, dict]):
        """
        experiments: {
            experiment_id: {
                "treatment_pct": 0.10,   # 10% traffic to treatment
                "status": "running",
                "override_users": [],     # always-treatment list (for QA)
            }
        }
        """
        self._experiments = experiments

    def assign(self, experiment_id: str, user_id: str) -> str:
        exp = self._experiments.get(experiment_id)
        if not exp or exp["status"] != "running":
            return "control"

        if user_id in exp.get("override_users", []):
            return "treatment"

        # Deterministic hash-based assignment — same user always gets same arm
        # Include experiment_id in hash to decorrelate across experiments
        hash_input = f"{experiment_id}:{user_id}".encode()
        hash_value = int(hashlib.sha256(hash_input).hexdigest(), 16)
        bucket = (hash_value % 10000) / 10000.0   # 0.0000 to 0.9999

        return "treatment" if bucket < exp["treatment_pct"] else "control"

    def get_active_experiments(self, user_id: str) -> dict[str, str]:
        """Return {experiment_id: arm} for all running experiments."""
        return {
            exp_id: self.assign(exp_id, user_id)
            for exp_id, cfg in self._experiments.items()
            if cfg["status"] == "running"
        }

from dataclasses import dataclass

@dataclass
class ExperimentGuardrails:
    max_latency_p95_ms: float     # abort if treatment exceeds this
    max_cost_per_call_tokens: int # abort if treatment exceeds this
    min_safety_refusal_rate: float # abort if treatment drops below this
    max_pii_rate: float            # abort if treatment exceeds this (zero-tolerance = 0.0)

def check_guardrails(
    experiment_id: str,
    treatment_metrics: dict,
    guardrails: ExperimentGuardrails,
) -> tuple[bool, str | None]:
    """
    Returns (should_abort, reason).
    Called daily during experiment runtime.
    """
    if treatment_metrics["latency_p95_ms"] > guardrails.max_latency_p95_ms:
        return True, (
            f"Latency guardrail breached: {treatment_metrics['latency_p95_ms']:.0f}ms > "            f"{guardrails.max_latency_p95_ms:.0f}ms"
        )
    if treatment_metrics["mean_tokens"] > guardrails.max_cost_per_call_tokens:
        return True, f"Cost guardrail breached: token budget exceeded"

    if treatment_metrics["safety_refusal_rate"] < guardrails.min_safety_refusal_rate:
        return True, (
            f"Safety guardrail breached: refusal rate "            f"{treatment_metrics['safety_refusal_rate']:.1%} < "            f"{guardrails.min_safety_refusal_rate:.1%}"
        )
    if treatment_metrics.get("pii_rate", 0) > guardrails.max_pii_rate:
        return True, f"PII guardrail breached: PII detected in treatment responses"

    return False, None
